def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres = Presentation(modified_ppt_path)
    slide = pres.slides[6]
    required_text = "Elevators control the pitch attitude of the aircraft"
    # Find textbox shape and diagram shape
    textbox_shape = None
    img_shape = None
    for shape in slide.shapes:
        if shape.has_text_frame and shape.text.strip() == required_text:
            textbox_shape = shape
        if shape.shape_type == 13:  # PICTURE (MSO_SHAPE_TYPE.PICTURE==13)
            img_shape = shape
    if textbox_shape is None:
        return ("Textbox with required text not found.", 0.0)
    if img_shape is None:
        return ("No image found on slide 7 to check diagram.", 0.0)
    # Check if the textbox is visually below the bottom of the image's coordinates
    textbox_top = textbox_shape.top
    textbox_height = textbox_shape.height
    image_top = img_shape.top
    image_height = img_shape.height
    if textbox_top > (image_top + image_height - 0.01*image_height):
        return ("Textbox is positioned below the diagram.", 1.0)
    else:
        return ("Textbox not below diagram (Y position check).", 0.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres = Presentation(modified_ppt_path)
    slide = pres.slides[6]
    required_text = "Elevators control the pitch attitude of the aircraft"
    textbox_shape = None
    img_shape = None
    for shape in slide.shapes:
        if shape.has_text_frame and shape.text.strip() == required_text:
            textbox_shape = shape
        if shape.shape_type == 13:
            img_shape = shape
    if textbox_shape is None or img_shape is None:
        return ("Textbox or image shape not found for overlap check.", 0.0)
    # Get bounding boxes (left, top, right, bottom)
    def get_bbox(shape):
        return (shape.left, shape.top, shape.left + shape.width, shape.top + shape.height)
    tbox = get_bbox(textbox_shape)
    ibox = get_bbox(img_shape)
    # Check for overlap
    overlap = not (tbox[2] < ibox[0] or tbox[0] > ibox[2] or tbox[3] < ibox[1] or tbox[1] > ibox[3])
    if overlap:
        return ("Textbox overlaps with diagram image.", 0.0)
    else:
        return ("No overlap between textbox and diagram image.", 1.0)

def compute_score() -> tuple[str, float]:
    # Allowable modifications: adding textbox, resizing/moving aircraft diagram image only on slide 7
    # No slide additions/removals. No removed shapes. No changes on other slides.
    # We'll use ppt_diff for this.
    extraneous = False
    reasons = []
    # No slides should be added/removed
    if ppt_diff.added_slides:
        extraneous = True
        reasons.append("Slides were added.")
    if ppt_diff.removed_slides:
        extraneous = True
        reasons.append("Slides were removed.")
    # Check changes/animations/transitions outside slide 7
    for anim in ppt_diff.added_animations + ppt_diff.removed_animations:
        if int(anim.slide_id) != 7:
            extraneous = True
            reasons.append(f"Animation added or removed to slide {anim.slide_id}.")
    for pre, post in ppt_diff.modified_animations:
        if int(pre.slide_id) != 7:
            extraneous = True
            reasons.append(f"Animation modified on slide {pre.slide_id}.")
    for st in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if int(st.slide_id) != 7:
            extraneous = True
            reasons.append(f"Transition added or removed on slide {st.slide_id}.")
    for pre, post in ppt_diff.modified_transitions:
        if int(pre.slide_id) != 7:
            extraneous = True
            reasons.append(f"Transition modified on slide {pre.slide_id}.")
    # Check that textbox and one image on slide 7 are all that's affected on slide 7
    # We'll allow added text, modified image (diagram), but not deleted content
    if ppt_diff.removed_animations:
        for anim in ppt_diff.removed_animations:
            if int(anim.slide_id) == 7:
                extraneous = True
                reasons.append("Content removed from slide 7.")
    # Check for extraneous slide-level or notes changes
    for i, (old_slide, new_slide) in enumerate(ppt_diff.modified_slides):
        snum = old_slide.slide_number
        if snum != 7:
            extraneous = True
            reasons.append(f"Unrelated change to slide {snum}.")
        # If notes were changed, that's extraneous
        if (old_slide.notes or '').strip() != (new_slide.notes or '').strip():
            extraneous = True
            reasons.append("Notes were changed on slide 7.")
    if extraneous:
        return ("; ".join(reasons), 0.0)
    else:
        return ("No extraneous changes detected.", 1.0)
